#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll n;    cin >> n;    ll count=0;    if(n==1){        cout<<0<<"\n";        return;    }        while(n>1){        if(n%6!=0){            n*=2;            count++;        }        else{            n/=6;            count++;        }    }    if(n==1) cout<<count<<"\n";    else cout<<-1<<"\n";        } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}